519→    public function ask(Request $request): JsonResponse
520→    {
521→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
522→        if (!$this->inWhitelist($sfuserId)) {
523→            \Log::info('[lbl][0416-AI日报][AiAsk] 无权限', ['sfuser_id' => $sfuserId]);
524→            return $this->responseJsonFail('无权限');
525→        }
526→        $roleId = $request->input('role_id');
527→        $sessionId = $request->input('session_id');
528→        $message = $request->input('message');
529→        $reportContext = $request->input('report_context', '');
530→        $reportContextRaw = $request->input('report_context_raw', '');
531→
532→        // 解压 report_context（前端 gzip+base64 压缩后以 "gz:" 前缀标识）
533→        if (str_starts_with($reportContext, 'gz:')) {
534→            $decoded = base64_decode(substr($reportContext, 3), true);
535→            $reportContext = $decoded !== false ? (gzdecode($decoded) ?: $reportContext) : $reportContext;
536→        }
537→        // 去除多余空白（连续空行压缩为单空行），减少发给 AI 的 token
538→        $reportContext = preg_replace('/\n{3,}/', "\n\n", trim($reportContext));
539→        \Log::info('[lbl][0416-AI日报][AiAsk] report_context size', [
540→            'bytes' => strlen($reportContext),
541→            'chars' => mb_strlen($reportContext),
542→        ]);
543→
544→        // 校验角色归属
545→        $role = DB::table('daily_report_ai_roles')
546→            ->where('id', $roleId)
547→            ->where('sfuser_id', $sfuserId)
548→            ->whereNull('deleted_at')
549→            ->first();
550→
551→        if (!$role) {
552→            return $this->responseJsonFail('角色不存在');
553→        }
554→
555→        // 创建或复用会话
556→        if (!$sessionId) {
557→            $title = mb_substr($message, 0, 20);
558→            $sessionId = DB::table('daily_report_ai_sessions')->insertGetId([
559→                'sfuser_id' => $sfuserId,
560→                'role_id' => $roleId,
561→                'title' => $title,
562→                'created_at' => now(),
563→                'updated_at' => now(),
564→            ]);
565→        } else {
566→            $sessionRow = DB::table('daily_report_ai_sessions')
567→                ->where('id', $sessionId)
568→                ->where('sfuser_id', $sfuserId)
569→                ->whereNull('deleted_at')
570→                ->first();
571→            if (!$sessionRow) {
572→                return $this->responseJsonFail('会话不存在');
573→            }
574→        }
575→
576→        // 解压 report_context_raw（与 report_context 相同的 gzip+base64 压缩格式）
577→        if (str_starts_with($reportContextRaw, 'gz:')) {
578→            $decoded = base64_decode(substr($reportContextRaw, 3), true);
579→            $reportContextRaw = $decoded !== false ? (gzdecode($decoded) ?: $reportContextRaw) : $reportContextRaw;
580→        }
581→
582→        // 保存同步日报上下文（如果有）—— 优先存原始 HTML，便于页面回显
583→        $contextToStore = !empty($reportContextRaw) ? $reportContextRaw : $reportContext;
584→        if (!empty($contextToStore)) {
585→            DB::table('daily_report_ai_messages')->insert([
586→                'session_id' => $sessionId,
587→                'role' => 'context',
588→                'content' => $contextToStore,
589→                'created_at' => now(),
590→            ]);
591→        }
592→
593→        // 保存用户消息
594→        DB::table('daily_report_ai_messages')->insert([
595→            'session_id' => $sessionId,
596→            'role' => 'user',
597→            'content' => $message,
598→            'created_at' => now(),
599→        ]);
600→
601→        // 更新会话时间
